SELECT dhb.dhb_name, vs.fully_vaccinated AS fully_vaccinated_count
FROM dhb
INNER JOIN vaccination_status vs ON dhb.dhb_id = vs.dhb_id;

SELECT dhb_name 
FROM dhb 
WHERE dhb_id = 1;

SELECT dhb_name, region, contact_email, contact_phone, website
FROM dhb
WHERE region = 'Auckland';

SELECT dhb_id, dhb_name
FROM dhb
WHERE dhb_id > 5;

SELECT vaccination_status
FROM vaccination_records
WHERE individual_id = 1;

SELECT T1.individual_id, T1.first_name, T1.last_name, T1.date_of_birth, T1.gender, T1.address, T1.email, T1.phone_number, T1.nhf_number
FROM individuals AS T1
INNER JOIN vaccination_appointments AS T2 ON T1.individual_id = T2.individual_id;

SELECT d.dhb_name, v.fully_vaccinated_percent
FROM dhb d
INNER JOIN vaccination_status v ON d.dhb_id = v.dhb_id
WHERE v.fully_vaccinated_percent = (
    SELECT MAX(fully_vaccinated_percent) FROM vaccination_status
);

SELECT COUNT(*) 
FROM vaccination_records 
WHERE vaccination_status = 'Full';
